#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding ophthalmology-assessment (16 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    first_name:string! \
    last_name:string! \
    date_of_birth:date \
    sex:string! \
    phone:string! \
    email:string! \
    address:text! \
    gp_name:string! \
    gp_practice:string! \
    optometrist_name:string! \
    --htmx

cargo loco generate scaffold assessment_chief_complaint \
    assessment:references \
    primary_complaint:text! \
    onset:string! \
    duration:text! \
    laterality:string! \
    associated_symptoms:text! \
    pain:string! \
    pain_severity:int \
    pain_character:string! \
    photophobia:string! \
    discharge:string! \
    discharge_description:text! \
    flashes_or_floaters:string! \
    flashes_floaters_details:text! \
    vision_loss:string! \
    vision_loss_details:text! \
    chief_complaint_notes:text! \
    --htmx

cargo loco generate scaffold assessment_visual_acuity \
    assessment:references \
    va_right_unaided:string! \
    va_left_unaided:string! \
    va_right_corrected:string! \
    va_left_corrected:string! \
    va_right_pinhole:string! \
    va_left_pinhole:string! \
    va_method:string! \
    near_vision_right:string! \
    near_vision_left:string! \
    current_spectacle_prescription:text! \
    refraction_right:text! \
    refraction_left:text! \
    auto_refraction_right:text! \
    auto_refraction_left:text! \
    colour_vision:string! \
    colour_vision_details:text! \
    visual_acuity_notes:text! \
    --htmx

cargo loco generate scaffold assessment_ocular_history \
    assessment:references \
    has_glaucoma:string! \
    glaucoma_details:text! \
    has_cataract:string! \
    cataract_details:text! \
    has_macular_degeneration:string! \
    macular_degeneration_details:text! \
    has_diabetic_retinopathy:string! \
    diabetic_retinopathy_details:text! \
    has_retinal_detachment:string! \
    retinal_detachment_details:text! \
    has_strabismus:string! \
    strabismus_details:text! \
    has_amblyopia:string! \
    amblyopia_details:text! \
    previous_eye_surgery:string! \
    eye_surgery_details:text! \
    previous_eye_trauma:string! \
    eye_trauma_details:text! \
    family_eye_history:text! \
    contact_lens_use:string! \
    contact_lens_details:text! \
    ocular_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_anterior_segment \
    assessment:references \
    lids_right:string! \
    lids_right_details:text! \
    lids_left:string! \
    lids_left_details:text! \
    conjunctiva_right:string! \
    conjunctiva_right_details:text! \
    conjunctiva_left:string! \
    conjunctiva_left_details:text! \
    cornea_right:string! \
    cornea_right_details:text! \
    cornea_left:string! \
    cornea_left_details:text! \
    anterior_chamber_right:string! \
    anterior_chamber_right_details:text! \
    anterior_chamber_left:string! \
    anterior_chamber_left_details:text! \
    iris_right:string! \
    iris_right_details:text! \
    iris_left:string! \
    iris_left_details:text! \
    lens_right:string! \
    lens_right_details:text! \
    lens_left:string! \
    lens_left_details:text! \
    iop_right_mmhg:double \
    iop_left_mmhg:double \
    iop_method:string! \
    iop_time:string \
    anterior_segment_notes:text! \
    --htmx

cargo loco generate scaffold assessment_posterior_segment \
    assessment:references \
    vitreous_right:string! \
    vitreous_right_details:text! \
    vitreous_left:string! \
    vitreous_left_details:text! \
    optic_disc_right:string! \
    optic_disc_right_details:text! \
    optic_disc_left:string! \
    optic_disc_left_details:text! \
    cup_disc_ratio_right:double \
    cup_disc_ratio_left:double \
    macula_right:string! \
    macula_right_details:text! \
    macula_left:string! \
    macula_left_details:text! \
    retinal_vessels_right:string! \
    retinal_vessels_right_details:text! \
    retinal_vessels_left:string! \
    retinal_vessels_left_details:text! \
    peripheral_retina_right:string! \
    peripheral_retina_right_details:text! \
    peripheral_retina_left:string! \
    peripheral_retina_left_details:text! \
    dilation_used:string! \
    dilating_agent:string! \
    posterior_segment_notes:text! \
    --htmx

cargo loco generate scaffold assessment_visual_field_pupils \
    assessment:references \
    confrontation_field_right:string! \
    confrontation_field_right_details:text! \
    confrontation_field_left:string! \
    confrontation_field_left_details:text! \
    formal_perimetry_performed:string! \
    perimetry_type:string! \
    perimetry_right_result:text! \
    perimetry_left_result:text! \
    mean_deviation_right:double \
    mean_deviation_left:double \
    pupil_right_size_mm:double \
    pupil_left_size_mm:double \
    pupil_right_shape:string! \
    pupil_left_shape:string! \
    pupil_right_reaction:string! \
    pupil_left_reaction:string! \
    rapd:string! \
    ocular_motility:string! \
    ocular_motility_details:text! \
    visual_field_pupils_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    has_ocular_medications:string! \
    has_systemic_medications:string! \
    medication_allergies:text! \
    medications_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medication_item \
    current_medications:references \
    medication_name:string! \
    dose:string! \
    frequency:string! \
    route:string! \
    eye:string! \
    indication:string! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_systemic_conditions \
    assessment:references \
    has_diabetes:string! \
    diabetes_type:string! \
    diabetes_duration_years:int \
    hba1c:double \
    has_hypertension:string! \
    hypertension_controlled:string! \
    has_thyroid_disease:string! \
    thyroid_disease_details:text! \
    has_autoimmune_disease:string! \
    autoimmune_disease_details:text! \
    has_cardiovascular_disease:string! \
    cardiovascular_disease_details:text! \
    has_neurological_disease:string! \
    neurological_disease_details:text! \
    smoking_status:string! \
    other_systemic_conditions:text! \
    systemic_conditions_notes:text! \
    --htmx

cargo loco generate scaffold assessment_functional_impact \
    assessment:references \
    reading_difficulty:string! \
    driving_ability:string! \
    dvla_notification_required:string! \
    screen_use_difficulty:string! \
    mobility_impact:string! \
    falls_risk:string! \
    work_impact:string! \
    daily_living_impact:string! \
    social_impact:string! \
    low_vision_aids_used:text! \
    low_vision_referral:string! \
    certificate_of_visual_impairment:string! \
    functional_impact_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    visual_acuity_grade:string! \
    best_corrected_va_right:string! \
    best_corrected_va_left:string! \
    better_eye_va:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
